  ('police-d442c1a4-moex-00238', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依司法院釋字第631號解釋意旨，關於憲法對秘密通訊之保障，下列敘述何者正確？', '["國家對人民秘密通訊之限制，如通過法律保留與比例原則之檢驗，即與憲法無違", "通訊監察書之聲請與核發，涉關個人權利之保障，而非權力分立之問題", "人民之秘密通訊自由僅能對抗國家之侵害，私人間之刺探竊聽行為純屬刑法規範事項，與 憲法完全無關", "通訊監察之執行，可能同時侵害受監察人及無辜第三人之秘密通訊自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00239', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '關於宗教自由保障之主體，下列敘述何者正確？', '["宗教自由之保障主體僅限於本國人，不包括外國人", "宗教自由之保障主體僅限於本國自然人，不包括本國法人及外國人", "宗教自由之保障主體僅限於本國及外國自然人，不包括法人", "宗教自由之保障主體包括自然人與法人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00240', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '下列敘述，何者與生存權之保障無涉？', '["優生保健法第9條允許墮胎之立法", "符合人性尊嚴之生活", "建立最低工資保障", "人民有信仰自由，得自行創立宗教"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00241', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '甲女與乙男結婚後懷有丙胎兒，甲女決定墮胎。墮胎最可能涉及到下列何種之基本權衝突情形？', '["甲女身體自決權與丙胎兒生存權", "甲女身體自決權與乙男家庭權", "丙胎兒生存權與甲女及乙男家庭權", "甲女身體自決權與丙胎兒自由權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00242', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '下列何者非屬對於人民職業選擇自由之主觀條件限制？', '["禁止曾犯特定罪者駕駛計程車為業", "藥師執業處所應以一處為限", "經主管機關核准之證券投資顧問事業方得舉辦證券投資講習", "公務員於其離職後三年內，不得擔任與其離職前五年內之職務直接相關之營利事業董事、 監察人、經理、執行業務之股東或顧問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00243', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '刑事訴訟法規定，被告經第一審判決無罪，但第二審變更為有罪判決者，不得上訴於第三審 法院，依司法院大法官解釋意旨，係爭規定是否違憲？', '["與憲法第16條保障人民訴訟權之意旨有違，違憲", "與憲法第7條保障人民平等權之意旨有違，違憲", "與憲法第23條信賴保護原則之意旨有違，違憲", "與憲法第23條比例原則之意旨有違，違憲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00244', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '關於服兵役義務，下列敘述何者錯誤？', '["服兵役屬義務，故就徵兵機關就役男應否服兵役及應服何種兵役所為之決定，不得救濟", "有關人民服兵役及其違背義務之制裁手段，應由立法機關衡酌國家安全、社會發展之需要， 以法律定之", "針對後備軍人意圖避免召集處理，而有居住處所遷移，無故不依規定申報之情事者，應處 以刑事罰或行政罰，屬立法機關得自由形成之權限", "如符合公平等條件，國家得實施替代役"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00245', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '憲法本文所規定之基本人權，下列何者兼具權利及義務之性質？', '["言論自由", "人身自由", "接受國民教育", "集會結社自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
  ('police-d442c1a4-moex-00246', 'police-d442c1a4', 'police-d442c1a4-moex-111-15a7b19c', 'sub-police-d442c1a4-01', NULL, 'single_choice', '依現行憲法增修條文相關內容規定，關於立法委員之選舉，下列何者錯誤？', '["任期四年，連選得連任", "採單一選區兩票制", "全國不分區及僑居國外國民立法委員依政黨名單投票選舉之，由獲得百分之五以上政黨票 之政黨依得票比率選出", "採聯立制兩票制，區域代表與政黨比例代表之選票分別計算，互不影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:08+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "511", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "國境警察人員"}'::jsonb, NULL),
